			int factorGroupId = memo.logicalGroupId(factorRelationId);
			int factorWinnerId = memo.findWinner(factorGroupId, anyPropertyId, 0, 0, 0);
			boolean connected = connectedToPrefix(factors, ordinal, factorRelationId);
