			if (existingGroups != null) {
				combinedSubset |= 1 << ordinal;
			}
			int targetGroupId = ordinal + 1 == factors.length
					? memo.logicalGroupId(rootRelationId)
					: existingGroups == null ? 0 : existingGroups[combinedSubset];
